{
  "name": "generacion-de-gloria-crm-backend",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "node src/server.js",
    "start": "node src/server.js"
  }
}

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const projectRoot = path.resolve(__dirname, "../../..");

const parseEnvFile = (filePath) => {
  try {
    const content = fs.readFileSync(filePath, "utf8");
    const lines = content.split(/\r?\n/);
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith("#")) continue;
      const separator = trimmed.indexOf("=");
      if (separator <= 0) continue;
      const key = trimmed.slice(0, separator).trim();
      const rawValue = trimmed.slice(separator + 1).trim();
      const value = rawValue.replace(/^['"]|['"]$/g, "");
      if (!(key in process.env)) {
        process.env[key] = value;
      }
    }
  } catch {}
};

parseEnvFile(path.join(projectRoot, ".env"));
parseEnvFile(path.join(projectRoot, ".env.local"));

const toBool = (value) => String(value || "").toLowerCase() === "true";
const normalizeUrl = (value) => String(value || "").replace(/\/+$/, "");
const normalizeSupabaseUrl = (value) =>
  normalizeUrl(value).replace(/\/rest\/v1$/i, "");

const supabaseUrl = normalizeSupabaseUrl(process.env.SUPABASE_URL);
const supabasePublishableKey = String(process.env.SUPABASE_PUBLISHABLE_KEY || "");
const supabaseSecretKey = String(
  process.env.SUPABASE_SECRET_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || ""
);
const allowInsecurePublishableWrite = toBool(
  process.env.SUPABASE_ALLOW_INSECURE_PUBLISHABLE_WRITE
);
const supabaseEnforceRemote = toBool(
  process.env.SUPABASE_ENFORCE_REMOTE || (supabaseUrl ? "true" : "false")
);

const storageDriver =
  supabaseUrl && (supabaseSecretKey || (allowInsecurePublishableWrite && supabasePublishableKey))
    ? "supabase"
    : "file";

export const env = {
  port: Number(process.env.PORT || 4000),
  jwtSecret: process.env.JWT_SECRET || "generacion-de-gloria-secret",
  dataFile: path.resolve(__dirname, "../data/database.json"),
  frontendRoot: path.resolve(__dirname, "../../../frontend"),
  supabaseUrl,
  supabasePublishableKey,
  supabaseSecretKey,
  supabaseTable: process.env.SUPABASE_TABLE || "crm_state",
  supabaseRecordId: process.env.SUPABASE_RECORD_ID || "generacion-de-gloria",
  allowInsecurePublishableWrite,
  supabaseEnforceRemote,
  storageDriver
};

const now = new Date().toISOString();

export const seedData = {
  meta: {
    churchName: "Ministerio Juvenil Generacion de Gloria",
    createdAt: now,
    updatedAt: now
  },
  users: [],
  youths: [],
  attendanceSessions: [],
  interactions: [],
  alerts: []
};

import fs from "node:fs/promises";
import { env } from "../config/env.js";
import { seedData } from "../data/seed.js";

let cache = null;
let lastStorageStatus = {
  activeDriver: env.storageDriver,
  intendedDriver: env.storageDriver,
  lastError: "",
  ready: env.storageDriver === "file"
};

const clone = (value) => structuredClone(value);

const inferBirthDate = (youth) => {
  if (youth.birthDate) return youth.birthDate;
  if (youth.fechaDeNacimiento) return youth.fechaDeNacimiento;
  const age = Number(youth.age);
  if (Number.isFinite(age) && age > 0 && age < 120) {
    return `${new Date().getFullYear() - age}-01-01`;
  }
  return "2000-01-01";
};

const normalizeData = (data) => ({
  meta: {
    ...seedData.meta,
    ...(data.meta || {})
  },
  users: Array.isArray(data.users)
    ? data.users.map((user) => ({
        assignedYouthIds: [],
        active: true,
        ...user,
        assignedYouthIds: Array.isArray(user.assignedYouthIds)
          ? user.assignedYouthIds
          : []
      }))
    : [],
  youths: Array.isArray(data.youths)
    ? data.youths.map((youth) => {
        const birthDate = inferBirthDate(youth);
        const currentAge = Number(youth.age);
        const birthYear = Number(birthDate.slice(0, 4));
        const derivedAge =
          Number.isFinite(currentAge) && currentAge > 0
            ? currentAge
            : Math.max(0, new Date().getFullYear() - birthYear);
        return {
          email: "",
          address: "",
          notes: "",
          status: "activo",
          assignedUserId: null,
          ...youth,
          age: derivedAge,
          documentId:
            youth.documentId ||
            youth.cedula ||
            youth.documento ||
            `SIN-DOCUMENTO-${youth.id || "LEGADO"}`,
          birthDate,
          baptized: youth.baptized || youth.bautizado || "NO",
          memberRole: youth.memberRole || youth.rolMiembro || youth.rol || "Miembro",
          updatedAt: youth.updatedAt || youth.createdAt || new Date().toISOString()
        };
      })
    : [],
  attendanceSessions: Array.isArray(data.attendanceSessions)
    ? data.attendanceSessions
    : [],
  interactions: Array.isArray(data.interactions) ? data.interactions : [],
  alerts: Array.isArray(data.alerts) ? data.alerts : []
});

const ensureLocalFile = async () => {
  try {
    await fs.access(env.dataFile);
  } catch {
    await fs.writeFile(env.dataFile, JSON.stringify(seedData, null, 2), "utf8");
  }
};

const markLocalReady = () => {
  lastStorageStatus = {
    ...lastStorageStatus,
    activeDriver: "file",
    lastError: env.storageDriver === "file" ? "" : lastStorageStatus.lastError,
    ready: true
  };
};

const readLocalDb = async () => {
  await ensureLocalFile();
  if (cache) {
    markLocalReady();
    return clone(cache);
  }
  const raw = await fs.readFile(env.dataFile, "utf8");
  cache = normalizeData(JSON.parse(raw));
  markLocalReady();
  return clone(cache);
};

const writeLocalDb = async (data) => {
  cache = normalizeData(data);
  await fs.writeFile(env.dataFile, JSON.stringify(cache, null, 2), "utf8");
  lastStorageStatus = {
    ...lastStorageStatus,
    activeDriver: "file",
    ready: true
  };
  return clone(cache);
};

const getSupabaseApiKey = () => {
  if (env.supabaseSecretKey) return env.supabaseSecretKey;
  if (env.allowInsecurePublishableWrite && env.supabasePublishableKey) {
    return env.supabasePublishableKey;
  }
  return "";
};

const isSupabaseEnabled = () =>
  env.storageDriver === "supabase" && Boolean(env.supabaseUrl && getSupabaseApiKey());

const supabaseHeaders = (extra = {}) => {
  const apiKey = getSupabaseApiKey();
  return {
    apikey: apiKey,
    Authorization: `Bearer ${apiKey}`,
    "Content-Type": "application/json",
    ...extra
  };
};

const supabaseEndpoint = (suffix = "") =>
  `${env.supabaseUrl}/rest/v1/${env.supabaseTable}${suffix}`;

const mapSupabaseError = (error) => {
  const raw = String(error?.message || error);
  if (raw.toLowerCase().includes("fetch failed")) {
    return "No fue posible conectarse con Supabase desde este equipo. Revisa internet, DNS, firewall o la URL del proyecto.";
  }
  if (raw.includes("SUPABASE_READ_FAILED:404")) {
    return "La tabla remota de Supabase no existe. Ejecuta docs/supabase-schema.sql en el SQL Editor.";
  }
  if (raw.includes("SUPABASE_WRITE_FAILED:404")) {
    return "Supabase esta configurado pero la tabla remota no existe para guardar informacion.";
  }
  if (raw.includes("SUPABASE_READ_FAILED:401") || raw.includes("SUPABASE_WRITE_FAILED:401")) {
    return "La clave de Supabase no es valida para este proyecto.";
  }
  if (raw.includes("SUPABASE_READ_FAILED:403") || raw.includes("SUPABASE_WRITE_FAILED:403")) {
    return "Supabase rechazo el acceso. Revisa permisos, RLS o la clave segura.";
  }
  return raw;
};

const upsertRemoteRow = async (payload) => {
  const response = await fetch(supabaseEndpoint("?on_conflict=id"), {
    method: "POST",
    headers: supabaseHeaders({
      Prefer: "resolution=merge-duplicates,return=representation"
    }),
    body: JSON.stringify([
      {
        id: env.supabaseRecordId,
        payload,
        updated_at: new Date().toISOString()
      }
    ])
  });

  if (!response.ok) {
    throw new Error(`SUPABASE_WRITE_FAILED:${response.status}`);
  }
};

const readRemoteDb = async () => {
  if (cache) return clone(cache);
  const response = await fetch(
    supabaseEndpoint(
      `?id=eq.${encodeURIComponent(env.supabaseRecordId)}&select=payload`
    ),
    {
      headers: supabaseHeaders()
    }
  );

  if (!response.ok) {
    throw new Error(`SUPABASE_READ_FAILED:${response.status}`);
  }

  const rows = await response.json();
  if (!rows.length) {
    cache = normalizeData(seedData);
    await upsertRemoteRow(cache);
    lastStorageStatus = {
      ...lastStorageStatus,
      activeDriver: "supabase",
      lastError: "",
      ready: true
    };
    return clone(cache);
  }

  cache = normalizeData(rows[0].payload);
  lastStorageStatus = {
    ...lastStorageStatus,
    activeDriver: "supabase",
    lastError: "",
    ready: true
  };
  return clone(cache);
};

const writeRemoteDb = async (data) => {
  cache = normalizeData(data);
  await upsertRemoteRow(cache);
  lastStorageStatus = {
    ...lastStorageStatus,
    activeDriver: "supabase",
    lastError: "",
    ready: true
  };
  return clone(cache);
};

const setRemoteFailure = (error) => {
  lastStorageStatus = {
    intendedDriver: "supabase",
    activeDriver: env.supabaseEnforceRemote ? "supabase" : "file",
    lastError: mapSupabaseError(error),
    ready: false
  };
};

export const readDb = async () => {
  if (isSupabaseEnabled()) {
    try {
      return await readRemoteDb();
    } catch (error) {
      setRemoteFailure(error);
      if (env.supabaseEnforceRemote) {
        const failure = new Error(lastStorageStatus.lastError);
        failure.status = 503;
        throw failure;
      }
      return readLocalDb();
    }
  }
  return readLocalDb();
};

export const writeDb = async (data) => {
  if (isSupabaseEnabled()) {
    try {
      return await writeRemoteDb(data);
    } catch (error) {
      setRemoteFailure(error);
      if (env.supabaseEnforceRemote) {
        const failure = new Error(lastStorageStatus.lastError);
        failure.status = 503;
        throw failure;
      }
      return writeLocalDb(data);
    }
  }
  return writeLocalDb(data);
};

export const probeStorage = async () => {
  try {
    await readDb();
    return getStorageInfo();
  } catch (error) {
    return {
      ...getStorageInfo(),
      lastError: mapSupabaseError(error),
      ready: false
    };
  }
};

export const getStorageInfo = () => ({
  driver: lastStorageStatus.activeDriver,
  intendedDriver: lastStorageStatus.intendedDriver,
  supabaseUrlConfigured: Boolean(env.supabaseUrl),
  publishableKeyConfigured: Boolean(env.supabasePublishableKey),
  serverKeyConfigured: Boolean(env.supabaseSecretKey),
  allowInsecurePublishableWrite: env.allowInsecurePublishableWrite,
  supabaseEnforceRemote: env.supabaseEnforceRemote,
  pendingSupabaseConfig:
    Boolean(env.supabasePublishableKey) &&
    (!env.supabaseUrl || (!env.supabaseSecretKey && !env.allowInsecurePublishableWrite)),
  lastError: lastStorageStatus.lastError,
  ready: lastStorageStatus.ready
});

import { seedData } from "../data/seed.js";
import { readDb, writeDb } from "../repositories/database.js";

await writeDb(seedData);
const data = await readDb();

console.log(
  JSON.stringify({
    users: data.users.length,
    youths: data.youths.length,
    attendanceSessions: data.attendanceSessions.length,
    interactions: data.interactions.length,
    alerts: data.alerts.length
  })
);

import fs from "node:fs/promises";
import http from "node:http";
import path from "node:path";
import { env } from "./config/env.js";
import { sendJson, sendText, notFound, getRequestBody, getQuery, setNoContent } from "./utils/http.js";
import { signToken, verifyToken } from "./utils/jwt.js";
import {
  attendAlert,
  bootstrapSystem,
  createAttendanceSession,
  createInteraction,
  createUser,
  createYouth,
  deleteUser,
  deleteYouth,
  exportYouthsExcelXml,
  getDashboard,
  getSetupStatus,
  getYouthTimeline,
  importYouthsFromCsv,
  importStructuredMembers,
  listAlerts,
  listAttendance,
  listInteractions,
  listUsers,
  listYouths,
  login,
  sanitizeUser,
  updateUser,
  updateYouth
} from "./services/crmService.js";
import { getStorageInfo, probeStorage, readDb } from "./repositories/database.js";

const getUserFromRequest = async (req) => {
  const auth = req.headers.authorization || "";
  if (!auth.startsWith("Bearer ")) return null;
  const token = auth.slice(7);
  const decoded = verifyToken(token, env.jwtSecret);
  const data = await readDb();
  const user = data.users.find((item) => item.id === decoded.sub);
  return user ? sanitizeUser(user) : null;
};

const serveStatic = async (req, res) => {
  const requestPath = req.url === "/" ? "/index.html" : req.url.split("?")[0];
  let decodedPath = "";
  try {
    decodedPath = decodeURIComponent(requestPath);
  } catch {
    notFound(res);
    return;
  }
  const relativePath = decodedPath.replace(/^[/\\]+/, "");
  const filePath = path.resolve(env.frontendRoot, relativePath);
  const frontendRoot = path.resolve(env.frontendRoot);
  if (!filePath.startsWith(`${frontendRoot}${path.sep}`) && filePath !== frontendRoot) {
    notFound(res);
    return;
  }
  try {
    const file = await fs.readFile(filePath);
    const ext = path.extname(filePath).toLowerCase();
    const types = {
      ".html": "text/html; charset=utf-8",
      ".js": "application/javascript; charset=utf-8",
      ".css": "text/css; charset=utf-8",
      ".json": "application/json; charset=utf-8",
      ".svg": "image/svg+xml",
      ".png": "image/png"
    };
    res.writeHead(200, { "Content-Type": types[ext] || "application/octet-stream" });
    res.end(file);
  } catch {
    try {
      const fallback = await fs.readFile(path.join(env.frontendRoot, "index.html"));
      res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
      res.end(fallback);
    } catch {
      notFound(res);
    }
  }
};

const withHandler = async (res, action) => {
  try {
    await action();
  } catch (error) {
    if (error.message === "JSON_INVALIDO") {
      sendJson(res, 400, { message: "El cuerpo de la solicitud no es JSON valido." });
      return;
    }
    if (error.message === "TOKEN_INVALIDO" || error.message === "TOKEN_EXPIRADO") {
      sendJson(res, 401, { message: "Sesion invalida o vencida." });
      return;
    }
    sendJson(res, error.status || 500, {
      message: error.message || "Ocurrio un error inesperado."
    });
  }
};

const server = http.createServer(async (req, res) => {
  if (req.method === "OPTIONS") {
    setNoContent(res);
    return;
  }

  const url = new URL(req.url, `http://${req.headers.host}`);

  if (url.pathname === "/api/health" && req.method === "GET") {
    await withHandler(res, async () => {
      const storage = await probeStorage();
      let setup = null;
      if (storage.ready) {
        setup = await getSetupStatus();
      }
      sendJson(res, 200, {
        ok: storage.ready,
        app: "Generacion de Gloria CRM",
        storage,
        setup
      });
    });
    return;
  }

  if (url.pathname === "/api/setup/status" && req.method === "GET") {
    await withHandler(res, async () => {
      sendJson(res, 200, await getSetupStatus());
    });
    return;
  }

  if (url.pathname === "/api/setup/bootstrap" && req.method === "POST") {
    await withHandler(res, async () => {
      sendJson(res, 201, await bootstrapSystem(await getRequestBody(req)));
    });
    return;
  }

  if (url.pathname === "/api/setup/import-members" && req.method === "POST") {
    await withHandler(res, async () => {
      const setup = await getSetupStatus();
      if (!setup.setupRequired) {
        const error = new Error(
          "La importacion inicial sin autenticacion solo esta disponible antes de crear el primer administrador."
        );
        error.status = 403;
        throw error;
      }
      sendJson(
        res,
        201,
        await importStructuredMembers(await getRequestBody(req), {
          bypassAdminCheck: true
        })
      );
    });
    return;
  }

  if (url.pathname === "/api/auth/login" && req.method === "POST") {
    await withHandler(res, async () => {
      const body = await getRequestBody(req);
      const user = await login(body);
      const token = signToken({ sub: user.id, role: user.role }, env.jwtSecret);
      sendJson(res, 200, { token, user });
    });
    return;
  }

  if (url.pathname.startsWith("/api/")) {
    await withHandler(res, async () => {
      const user = await getUserFromRequest(req);
      if (!user) {
        sendJson(res, 401, { message: "Debes iniciar sesion." });
        return;
      }

      if (url.pathname === "/api/me" && req.method === "GET") {
        sendJson(res, 200, { user, system: { storage: getStorageInfo() } });
        return;
      }
      if (url.pathname === "/api/dashboard" && req.method === "GET") {
        sendJson(res, 200, await getDashboard(user));
        return;
      }
      if (url.pathname === "/api/youths" && req.method === "GET") {
        sendJson(res, 200, await listYouths(user, getQuery(req)));
        return;
      }
      if (url.pathname === "/api/youths" && req.method === "POST") {
        sendJson(res, 201, await createYouth(user, await getRequestBody(req)));
        return;
      }
      if (url.pathname.match(/^\/api\/youths\/[^/]+$/) && req.method === "PUT") {
        const youthId = url.pathname.split("/").pop();
        sendJson(res, 200, await updateYouth(user, youthId, await getRequestBody(req)));
        return;
      }
      if (url.pathname.match(/^\/api\/youths\/[^/]+$/) && req.method === "DELETE") {
        const youthId = url.pathname.split("/").pop();
        await deleteYouth(user, youthId);
        setNoContent(res);
        return;
      }
      if (url.pathname.match(/^\/api\/youths\/[^/]+\/timeline$/) && req.method === "GET") {
        const youthId = url.pathname.split("/")[3];
        sendJson(res, 200, await getYouthTimeline(user, youthId));
        return;
      }
      if (url.pathname === "/api/attendance" && req.method === "GET") {
        sendJson(res, 200, await listAttendance(user));
        return;
      }
      if (url.pathname === "/api/attendance" && req.method === "POST") {
        sendJson(
          res,
          201,
          await createAttendanceSession(user, await getRequestBody(req))
        );
        return;
      }
      if (url.pathname === "/api/interactions" && req.method === "GET") {
        sendJson(res, 200, await listInteractions(user));
        return;
      }
      if (url.pathname === "/api/interactions" && req.method === "POST") {
        sendJson(res, 201, await createInteraction(user, await getRequestBody(req)));
        return;
      }
      if (url.pathname === "/api/alerts" && req.method === "GET") {
        sendJson(res, 200, await listAlerts(user));
        return;
      }
      if (url.pathname.match(/^\/api\/alerts\/[^/]+\/attend$/) && req.method === "PATCH") {
        const alertId = url.pathname.split("/")[3];
        sendJson(res, 200, await attendAlert(user, alertId));
        return;
      }
      if (url.pathname === "/api/users" && req.method === "GET") {
        sendJson(res, 200, await listUsers(user));
        return;
      }
      if (url.pathname === "/api/users" && req.method === "POST") {
        sendJson(res, 201, await createUser(user, await getRequestBody(req)));
        return;
      }
      if (url.pathname.match(/^\/api\/users\/[^/]+$/) && req.method === "PUT") {
        const userId = url.pathname.split("/").pop();
        sendJson(res, 200, await updateUser(user, userId, await getRequestBody(req)));
        return;
      }
      if (url.pathname.match(/^\/api\/users\/[^/]+$/) && req.method === "DELETE") {
        const userId = url.pathname.split("/").pop();
        await deleteUser(user, userId);
        setNoContent(res);
        return;
      }
      if (url.pathname === "/api/export/youths" && req.method === "GET") {
        const xml = await exportYouthsExcelXml(user);
        sendText(res, 200, xml, {
          "Content-Type": "application/vnd.ms-excel; charset=utf-8",
          "Content-Disposition": "attachment; filename=jovenes.xls"
        });
        return;
      }
      if (url.pathname === "/api/import/youths" && req.method === "POST") {
        sendJson(res, 201, await importYouthsFromCsv(user, await getRequestBody(req)));
        return;
      }
      if (url.pathname === "/api/import/members" && req.method === "POST") {
        sendJson(
          res,
          201,
          await importStructuredMembers(await getRequestBody(req), { user })
        );
        return;
      }

      notFound(res);
    });
    return;
  }

  await serveStatic(req, res);
});

server.listen(env.port, () => {
  console.log(`CRM server running on port ${env.port}`);
});

import { readDb, writeDb } from "../repositories/database.js";
import {
  createId,
  normalizeText,
  nowIso,
  sameMonth,
  sameWeek,
  sortByDateDesc
} from "../utils/helpers.js";
import { comparePassword, hashPassword } from "../utils/security.js";

const youthVisibilityFilter = (user) => (youth) =>
  user.role === "ADMIN" || youth.assignedUserId === user.id;

const ensureYouthAccess = (user, youth) => {
  if (!youth) {
    const error = new Error("Joven no encontrado.");
    error.status = 404;
    throw error;
  }
  if (user.role === "ADMIN" || youth.assignedUserId === user.id) {
    return youth;
  }
  const error = new Error("No tienes acceso a este joven.");
  error.status = 403;
  throw error;
};

const syncUserAssignments = (data) => {
  const assignedByUser = new Map(data.users.map((user) => [user.id, []]));
  const validUserIds = new Set(data.users.map((user) => user.id));

  data.youths = data.youths.map((youth) => {
    if (!youth.assignedUserId) return youth;
    if (!validUserIds.has(youth.assignedUserId)) {
      return { ...youth, assignedUserId: null };
    }
    assignedByUser.get(youth.assignedUserId).push(youth.id);
    return youth;
  });

  data.users = data.users.map((user) => ({
    ...user,
    assignedYouthIds: assignedByUser.get(user.id) || []
  }));
};

const sanitizeUserWithAssignments = (data, user) => ({
  ...sanitizeUser(user),
  assignedYouthIds: data.youths
    .filter((youth) => youth.assignedUserId === user.id)
    .map((youth) => youth.id)
});

const escapeXml = (value) =>
  String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");

const validateYouthPayload = (payload) => {
  const fullName = normalizeText(payload.fullName);
  const documentId = normalizeText(payload.documentId || payload.cedula);
  const address = normalizeText(payload.address);
  const phone = normalizeText(payload.phone);
  const email = normalizeText(payload.email).toLowerCase();
  const birthDate = normalizeText(payload.birthDate || payload.fechaNacimiento);
  const baptizedRaw = normalizeText(payload.baptized || payload.bautizado || "NO");
  const memberRole = normalizeText(
    payload.memberRole || payload.rolMiembro || payload.role || "Miembro"
  );
  const joinDate = normalizeText(payload.joinDate);
  const status = normalizeText(payload.status || "activo").toLowerCase();
  const age = Number(payload.age);
  if (!fullName || !documentId || !phone || !birthDate) {
    const error = new Error("Datos del joven incompletos o invalidos.");
    error.status = 400;
    throw error;
  }
  if (!["activo", "inactivo"].includes(status)) {
    const error = new Error("Estado no valido.");
    error.status = 400;
    throw error;
  }
  const roleMap = {
    miembro: "Miembro",
    lider: "Lider",
    "co_lider": "Lider",
    colider: "Lider",
    mentor: "Mentor",
    diacono: "Diacono"
  };
  const normalizedRoleKey = memberRole
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");
  const normalizedRole = roleMap[normalizedRoleKey];
  if (!normalizedRole) {
    const error = new Error("Rol ministerial no valido.");
    error.status = 400;
    throw error;
  }
  const baptizedNormalized = ["SI", "NO"].includes(baptizedRaw.toUpperCase())
    ? baptizedRaw.toUpperCase()
    : null;
  if (!baptizedNormalized) {
    const error = new Error("El campo bautizados solo permite SI o NO.");
    error.status = 400;
    throw error;
  }
  const derivedAge =
    Number.isNaN(age) || age <= 0
      ? Math.max(
          0,
          new Date().getFullYear() - new Date(`${birthDate}T00:00:00`).getFullYear()
        )
      : age;
  return {
    fullName,
    documentId,
    age: derivedAge,
    phone,
    email,
    birthDate,
    baptized: baptizedNormalized,
    memberRole: normalizedRole,
    address,
    joinDate: joinDate || new Date().toISOString().slice(0, 10),
    status,
    assignedUserId: payload.assignedUserId || null,
    notes: normalizeText(payload.notes)
  };
};

const validateUserPayload = (payload) => {
  const fullName = normalizeText(payload.fullName);
  const email = normalizeText(payload.email).toLowerCase();
  const role = normalizeText(payload.role).toUpperCase();
  if (!fullName || !email || !["ADMIN", "ASISTENTE"].includes(role)) {
    const error = new Error("Datos de usuario invalidos.");
    error.status = 400;
    throw error;
  }
  return {
    fullName,
    email,
    role,
    active: payload.active !== false,
    assignedYouthIds: Array.isArray(payload.assignedYouthIds)
      ? payload.assignedYouthIds
      : []
  };
};

const recalculateAlerts = (data) => {
  const attendedAlerts = data.alerts.filter((alert) => alert.status === "atendida");
  const autoAlerts = [];
  const sessions = [...data.attendanceSessions].sort((a, b) =>
    a.date.localeCompare(b.date)
  );

  for (const youth of data.youths) {
    let misses = 0;
    let lastAbsentDate = null;
    for (const session of sessions) {
      const record = session.attendance.find((item) => item.youthId === youth.id);
      if (!record) continue;
      if (record.present) {
        misses = 0;
      } else {
        misses += 1;
        lastAbsentDate = session.date;
      }
      if (misses >= 2) {
        const generatedAt = `${lastAbsentDate}T00:00:00.000Z`;
        const alreadyHandled = attendedAlerts.some(
          (alert) =>
            alert.youthId === youth.id &&
            alert.reason === "2 ausencias consecutivas" &&
            alert.generatedAt === generatedAt
        );
        if (alreadyHandled) {
          misses = 0;
          lastAbsentDate = null;
          continue;
        }
        autoAlerts.push({
          id: `auto_${youth.id}_${lastAbsentDate.replace(/[^0-9]/g, "")}`,
          youthId: youth.id,
          reason: "2 ausencias consecutivas",
          status: "pendiente",
          generatedAt,
          attendedAt: null,
          attendedBy: null
        });
        break;
      }
    }
  }

  data.alerts = [...attendedAlerts, ...autoAlerts];
};

