      localStorage.setItem(tokenKey, data.token);
      setToken(data.token);
      setUser(data.user);
      await bootstrap(data.token);
      showMessage("Sesion iniciada correctamente.");
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

